function dateToNs(dateStr) {
  return BigInt(new Date(dateStr).getTime()) * 1000000n;
}
function calcBillTotals(items) {
  let subtotal = 0;
  let totalGST = 0;
  for (const item of items) {
    const amount = Number(item.quantity) * Number(item.unitPrice);
    totalGST += Number(item.gstAmount);
    subtotal += amount - Number(item.gstAmount);
  }
  return {
    subtotal: BigInt(Math.round(subtotal)),
    totalGST: BigInt(Math.round(totalGST))
  };
}
function makeItem(medId, qty, unitPrice, gstPct, hsnCode) {
  const amount = qty * unitPrice;
  const gstAmount = amount - amount / (1 + gstPct / 100);
  return {
    medicineId: medId,
    quantity: BigInt(qty),
    unitPrice: BigInt(unitPrice),
    gstAmount: BigInt(Math.round(gstAmount)),
    discountPercent: 0n,
    hsnCode
  };
}
